create or replace function public.adjust_remaining_sessions(   p_pass_id uuid,   p_amount integer,   p_reason text,   p_actor_id uuid ) returns void language plpgsql security definer set search_path = public as $$ declare   v_pass public.member_passes%rowtype;   v_actor public.staff_users%rowtype;   v_reason text := trim(coalesce(p_reason, ''));   v_new_remaining integer; begin   if char_length(v_reason) < 2 then     raise exception '?붿뿬 ?잛닔 議곗젙 ?ъ쑀瑜??낅젰??二쇱꽭??';   end if;   if p_amount = 0 then     raise exception '議곗젙 ?잛닔媛 0?낅땲??';   end if;   v_actor := public.assert_staff_actor(p_actor_id, array['owner','admin']);   select * into v_pass   from public.member_passes   where id = p_pass_id   for update;   if not found then     raise exception '?뚯썝沅뚯쓣 李얠쓣 ???놁뒿?덈떎.';   end if;   if v_actor.organization_id <> v_pass.organization_id then     raise exception '?ㅻⅨ 議곗쭅???뚯썝沅뚯? ?섏젙?????놁뒿?덈떎.';   end if;   if v_pass.status = 'cancelled' then     raise exception '痍⑥냼???뚯썝沅뚯? 議곗젙?????놁뒿?덈떎.';   end if;   v_new_remaining := least(v_pass.total_sessions, greatest(v_pass.remaining_sessions + p_amount, 0));   update public.member_passes   set remaining_sessions = v_new_remaining,       used_sessions = greatest(total_sessions - v_new_remaining, 0),       status = case         when v_new_remaining = 0 then 'used_up'         when status = 'used_up' and v_new_remaining > 0 then 'active'         else status       end,       updated_at = now()   where id = p_pass_id;   insert into public.audit_logs(     organization_id,     actor_id,     action,     entity_type,     entity_id,     before_data,     after_data   ) values (     v_pass.organization_id,     p_actor_id,     'PASS_REMAINING_ADJUSTED',     'member_passes',     p_pass_id,     to_jsonb(v_pass),     jsonb_build_object('amount', p_amount, 'reason', v_reason, 'remaining_after', v_new_remaining)   ); end; $$;
